    display: flex; align-items: flex-start; gap: 10px;
    font-size: 0.875rem; color: var(--texto-suave);
  }
  .attr-list li::before { content: '→'; flex-shrink: 0; font-weight: 700; margin-top: 1px; }

  .divider { height: 1px; background: var(--crema-oscuro); margin: 16px 0; }

  /* colors per user type */
  .u1 .user-avatar { background: #e8f5e9; }
  .u1 .user-info h3 { color: var(--verde-tierra); }
  .u1 .user-info .role { color: var(--verde-medio); }
  .u1 .attr-list li::before { color: var(--verde-claro); }

  .u2 .user-avatar { background: #e3f2fd; }
  .u2 .user-info h3 { color: var(--agua); }
  .u2 .user-info .role { color: var(--agua-claro); }
  .u2 .attr-list li::before { color: var(--agua-claro); }

  .u3 .user-avatar { background: #fff3e0; }
