  .u3 .attr-list li::before { color: var(--ocre); }

  .u4 .user-avatar { background: #fce4ec; }
  .u4 .user-info h3 { color: #880e4f; }
  .u4 .user-info .role { color: #c2185b; }
  .u4 .attr-list li::before { color: #c2185b; }

  /* ── NEEDS SECTION ── */
  .needs-layout {
    display: grid; grid-template-columns: 240px 1fr; gap: 32px; align-items: start;
  }
  @media (max-width: 700px) { .needs-layout { grid-template-columns: 1fr; } }

  .needs-nav { position: sticky; top: 80px; }
  .needs-nav-btn {
    display: flex; align-items: center; gap: 12px;
    width: 100%; padding: 12px 16px; border: none;
    background: none; cursor: pointer; border-radius: 10px;
    text-align: left; transition: all 0.15s; margin-bottom: 4px;
  }
  .needs-nav-btn:hover { background: var(--crema-oscuro); }
