    display: flex; align-items: center; gap: 8px; font-size: 0.8rem; color: var(--texto-suave);
  }
  .legend-dot { width: 12px; height: 12px; border-radius: 50%; }

  .flow-svg-wrap {
    background: #fff; border: 1px solid var(--borde); border-radius: 16px; padding: 32px;
    min-width: 900px;
  }

  /* ── FLOW NODES ── */
  .flow-grid {
    display: grid;
    grid-template-columns: repeat(8, 1fr);
    gap: 0;
    position: relative;
  }

  .flow-col {
    display: flex; flex-direction: column; align-items: center;
    position: relative; padding: 0 4px;
  }

  .flow-node {
    width: 100%; max-width: 110px;
    border-radius: 12px; padding: 12px 10px;
