  /* node color themes */
  .n-prep   { background: #f3e5f5; border-color: #ce93d8; color: #4a148c; }
  .n-s1     { background: #e8f5e9; border-color: #a5d6a7; color: #1b5e20; }
  .n-s2     { background: #fff3e0; border-color: #ffcc80; color: #e65100; }
  .n-s3     { background: #e3f2fd; border-color: #90caf9; color: #0d47a1; }
  .n-s4     { background: #fffde7; border-color: #fff176; color: #f57f17; }
  .n-s5     { background: #e8f5e9; border-color: #66bb6a; color: #2e7d32; }
