  }

  /* CONNECTOR LINES */
  .connectors-svg {
    width: 100%; height: 60px; overflow: visible;
    margin-top: -20px; position: relative; z-index: 1;
  }

  /* USER PATH BADGES */
  .user-paths {
    display: flex; justify-content: center; gap: 4px; margin-top: 8px;
