  }

  /* OUTCOME BOXES */
  .outcomes-grid {
    display: grid; grid-template-columns: repeat(4, 1fr); gap: 12px;
    margin-top: 40px;
  }
  @media (max-width: 800px) { .outcomes-grid { grid-template-columns: repeat(2, 1fr); } }

  .outcome-box {
    background: #fff; border: 1px solid var(--borde); border-radius: 12px;
    padding: 20px 16px; text-align: center;
  }
  .outcome-box .ob-icon { font-size: 2rem; margin-bottom: 10px; }
  .outcome-box h4 {
    font-family: 'Playfair Display', serif; font-size: 0.95rem;
    font-weight: 700; margin-bottom: 6px; color: var(--verde-tierra);
  }
  .outcome-box p { font-size: 0.78rem; color: var(--texto-suave); line-height: 1.5; }

  /* FULL FLOW: vertical timeline version */
  .timeline { position: relative; padding-left: 56px; }
  .timeline::before {
    content: ''; position: absolute; left: 20px; top: 0; bottom: 0;
    width: 3px; background: linear-gradient(to bottom, var(--verde-claro), var(--agua), var(--fuego));
    border-radius: 2px;
  }

  .tl-item { position: relative; margin-bottom: 32px; }
  .tl-dot {
    position: absolute; left: -44px; top: 8px;
    width: 36px; height: 36px; border-radius: 50%;
