  .tl-card-head {
    display: flex; align-items: center; gap: 12px; margin-bottom: 12px;
  }
  .tl-phase {
    font-family: 'Space Mono', monospace; font-size: 10px;
    letter-spacing: 1.5px; text-transform: uppercase;
  }
  .tl-week {
    margin-left: auto; font-family: 'Space Mono', monospace;
    font-size: 10px; background: var(--crema-oscuro); padding: 3px 10px; border-radius: 20px;
    color: var(--texto-suave);
  }
  .tl-card h3 {
    font-family: 'Playfair Display', serif; font-size: 1.1rem; font-weight: 700;
    margin-bottom: 6px;
  }
  .tl-card > p { font-size: 0.85rem; color: var(--texto-suave); margin-bottom: 12px; }

  .tl-acts {
    display: grid; grid-template-columns: repeat(auto-fill, minmax(160px, 1fr)); gap: 6px;
  }
  .tl-act {
    background: var(--crema-oscuro); border-radius: 8px; padding: 7px 10px;
    font-size: 0.78rem; color: var(--texto);
    display: flex; align-items: center; gap: 7px;
  }
  .tl-act .ta-icon { flex-shrink: 0; }

  .tl-product {
    margin-top: 12px; padding: 10px 14px;
    border-radius: 8px; display: flex; align-items: center; gap: 10px;
