  .act-proposito { background: var(--modulo-bg); border: 1px solid rgba(61,155,191,0.25); border-radius: 10px; padding: 16px 20px; margin-bottom: 20px; }
  .act-proposito .ap-label { font-family: 'Space Mono', monospace; font-size: 9px; letter-spacing: 2px; text-transform: uppercase; color: var(--modulo-color); margin-bottom: 8px; }
  .act-proposito ul { list-style: none; display: flex; flex-wrap: wrap; gap: 8px; }
  .act-proposito ul li { background: #fff; border: 1px solid rgba(26,107,138,0.25); color: var(--modulo-color); padding: 4px 12px; border-radius: 100px; font-size: 0.8rem; font-weight: 500; }
  .act-steps { margin: 20px 0; }
  .act-step { display: flex; gap: 16px; margin-bottom: 14px; align-items: flex-start; }
  .act-step-num { width: 28px; height: 28px; background: var(--modulo-light); color: #fff; border-radius: 50%; display: flex; align-items: center; justify-content: center; font-family: 'Space Mono', monospace; font-size: 0.75rem; font-weight: 700; flex-shrink: 0; margin-top: 2px; }
  .act-step p { margin: 0; color: var(--texto-suave); font-size: 0.95rem; line-height: 1.6; }
  .act-italic-note { font-style: italic; color: var(--semilla); background: var(--crema); border-left: 3px solid var(--ocre); padding: 12px 18px; border-radius: 0 8px 8px 0; margin: 20px 0; font-size: 0.9rem; }
  .tabla-wrap { overflow-x: auto; margin: 20px 0; }
  .tabla-rea { width: 100%; border-collapse: collapse; font-size: 0.88rem; }
  .tabla-rea th { background: var(--modulo-color); color: #fff; padding: 12px 16px; text-align: left; font-family: 'Space Mono', monospace; font-size: 9px; letter-spacing: 2px; text-transform: uppercase; }
  .tabla-rea td { padding: 14px 16px; border-bottom: 1px solid var(--borde); color: var(--texto-suave); vertical-align: top; }
  .tabla-rea tr:nth-child(even) td { background: var(--crema); }
  .dua-block { background: linear-gradient(135deg, rgba(26,107,138,0.05), rgba(61,155,191,0.08)); border: 1px solid rgba(26,107,138,0.2); border-radius: 12px; padding: 24px 28px; margin-top: 24px; }
  .dua-header { display: flex; align-items: center; gap: 10px; margin-bottom: 16px; }
  .dua-header .dua-icon { font-size: 1.3rem; }
  .dua-header .dua-title { font-family: 'Space Mono', monospace; font-size: 10px; letter-spacing: 2px; text-transform: uppercase; color: var(--modulo-color); font-weight: 700; }
  .dua-links { display: flex; flex-direction: column; gap: 10px; }
  .dua-link { display: flex; gap: 12px; align-items: center; background: #fff; border: 1px solid rgba(26,107,138,0.15); border-radius: 10px; padding: 12px 16px; text-decoration: none; transition: all 0.2s; }
  .dua-link:hover { background: rgba(26,107,138,0.04); border-color: var(--modulo-color); transform: translateX(4px); }
  .dua-link .dl-emoji { font-size: 1.2rem; flex-shrink: 0; }
  .dua-link .dl-label { font-size: 0.75rem; font-weight: 600; color: var(--modulo-color); font-family: 'Space Mono', monospace; text-transform: uppercase; letter-spacing: 1px; }
  .dua-link .dl-name { font-size: 0.9rem; color: var(--texto); font-weight: 500; }
  .canvas-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(280px, 1fr)); gap: 16px; margin-top: 20px; }
  .canvas-item { background: #fff; border: 1px solid rgba(26,107,138,0.2); border-radius: 12px; padding: 20px; border-top: 3px solid var(--modulo-light); }
  .canvas-item .ci-label { font-family: 'Space Mono', monospace; font-size: 9px; letter-spacing: 2px; text-transform: uppercase; color: var(--modulo-color); margin-bottom: 6px; }
  .canvas-item h4 { font-family: 'Playfair Display', serif; font-size: 1rem; font-weight: 700; color: var(--modulo-color); margin-bottom: 8px; }
  .canvas-item p { font-size: 0.85rem; color: var(--texto-suave); line-height: 1.6; margin: 0; }
  .canvas-item ul { list-style: none; }
  .canvas-item ul li { font-size: 0.85rem; color: var(--texto-suave); padding: 3px 0; }
  .canvas-item ul li::before { content: '→ '; color: var(--modulo-light); }
  .export-note { background: var(--crema-oscuro); border: 1px solid var(--borde); border-radius: 12px; padding: 20px 24px; margin-top: 48px; display: flex; gap: 12px; font-size: 0.88rem; color: var(--texto-suave); }
  @media (max-width: 600px) { .hero { padding: 40px 20px 32px; } .act-body, .act-head { padding: 20px; } }
